import{_ as i,o as a,c as e,a2 as l}from"./chunks/framework.DZrHScmQ.js";const u=JSON.parse('{"title":"Contributing to Evolution Handbook","description":"","frontmatter":{},"headers":[],"relativePath":"CONTRIBUTING.md","filePath":"CONTRIBUTING.md"}'),d={name:"CONTRIBUTING.md"};function o(r,t,n,h,s,p){return a(),e("div",null,[...t[0]||(t[0]=[l(`<h1 id="contributing-to-evolution-handbook" tabindex="-1">Contributing to Evolution Handbook <a class="header-anchor" href="#contributing-to-evolution-handbook" aria-label="Permalink to &quot;Contributing to Evolution Handbook&quot;">​</a></h1><p>Evolution Handbook 由团队共同维护。任何成员都可以修正文档、补充实践、提交案例或挑战现有结论。</p><p>贡献的目标不是一次写出完美标准，而是让真实经验以可审查、可演进的方式进入组织知识库。</p><h2 id="最快的参与方式" tabindex="-1">最快的参与方式 <a class="header-anchor" href="#最快的参与方式" aria-label="Permalink to &quot;最快的参与方式&quot;">​</a></h2><p>低风险修改可以走 fast path：小 PR、少说明、快速 Review。</p><p>适合 fast path：</p><ul><li>typo、格式、断链</li><li>README 导航</li><li>索引同步</li><li>明确过期描述</li><li>Draft 的限制、反例或小案例补充</li></ul><p>不适合 fast path：</p><ul><li>Standard、治理、安全、权限</li><li>项目契约和 breaking change</li><li>涉及生产、结算、客户或私密数据的内容</li></ul><p>其他修改可以直接建立分支并提交 Pull Request：</p><ul><li>更新根目录或子目录 <code>README.md</code></li><li>补充来源、术语和导航</li><li>更新已确认的项目或仓库状态</li><li>为现有文档增加反例、限制或验证证据</li></ul><p>不确定归属或尚未形成完整结论时：</p><ol><li>提交 Knowledge Candidate Issue；或</li><li>建立 Draft PR，在描述中写清已知事实和待讨论问题。</li></ol><h2 id="标准贡献流程" tabindex="-1">标准贡献流程 <a class="header-anchor" href="#标准贡献流程" aria-label="Permalink to &quot;标准贡献流程&quot;">​</a></h2><ol><li>阅读 <code>WORKSPACE.md</code>，判断内容属于组织、项目还是仓库。</li><li>搜索是否已有真源，避免创建重复正文。</li><li>新内容默认标记为 <code>Draft</code> 或 <code>Pattern Candidate</code>。</li><li>更新所在目录的 <code>README.md</code> 索引。</li><li>新增或调整项目、仓库时同步更新相关项目文档。</li><li>提交 PR，说明问题、变化、依据和验证。</li><li>根据影响范围邀请相关 Reviewer。</li></ol><h2 id="分级审查" tabindex="-1">分级审查 <a class="header-anchor" href="#分级审查" aria-label="Permalink to &quot;分级审查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>变更类型</th><th>示例</th><th>合并要求</th></tr></thead><tbody><tr><td>Level 0 编辑性</td><td>拼写、格式、链接、导航</td><td>任一团队成员审查</td></tr><tr><td>Level 1 补充性</td><td>Draft、Reference、案例候选</td><td>至少一名相关领域成员审查</td></tr><tr><td>Level 2 约束性</td><td>Adopted Practice、项目契约、项目归属</td><td>相关 Owner 或受影响项目代表审查</td></tr><tr><td>Level 3 组织性</td><td>Standard、治理、安全、权限和跨项目默认规则</td><td>相关 Owner 明确批准，并列出影响与迁移方式</td></tr></tbody></table><p>Reviewer 数量不是目的。关键是让承担影响的人参与审查，且高影响规则不能仅凭文案质量合并。</p><h2 id="pr-应回答" tabindex="-1">PR 应回答 <a class="header-anchor" href="#pr-应回答" aria-label="Permalink to &quot;PR 应回答&quot;">​</a></h2><ul><li>解决什么问题？</li><li>这是事实、建议、候选实践还是既有标准？</li><li>影响哪些项目、仓库或角色？</li><li>证据或来源是什么？</li><li>如何验证？有哪些限制或反例？</li><li>是否引入新的真源或需要迁移旧文档？</li></ul><p>仓库提供了 Pull Request 模板，简单修改可以删除不适用项。</p><h2 id="本地检查" tabindex="-1">本地检查 <a class="header-anchor" href="#本地检查" aria-label="Permalink to &quot;本地检查&quot;">​</a></h2><p>提交 PR 前建议运行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> check</span></span></code></pre></div><p>当前检查覆盖 Markdown 基础格式和文档 metadata。CI 只是基础防线，不代表事实、来源、状态、Owner 和隐私边界已经完成核对；这些仍由提交者和 Reviewer 负责。</p><h2 id="readme-也可以直接更新" tabindex="-1">README 也可以直接更新 <a class="header-anchor" href="#readme-也可以直接更新" aria-label="Permalink to &quot;README 也可以直接更新&quot;">​</a></h2><p>README 是入口，不是只读封面。发现以下问题时请直接修改：</p><ul><li>新成员不知道从哪里开始</li><li>目录结构已经变化</li><li>常用入口没有被链接</li><li>项目状态描述与事实不符</li><li>贡献方式不够清楚</li></ul><p>README 只保存导航和稳定概述。较长规则应进入对应目录，再从 README 链接。</p><h2 id="使用-agent-贡献" tabindex="-1">使用 Agent 贡献 <a class="header-anchor" href="#使用-agent-贡献" aria-label="Permalink to &quot;使用 Agent 贡献&quot;">​</a></h2><p>可以使用 Codex、Claude Code 或其他 Agent 帮助整理内容，但提交者仍需：</p><ul><li>核对事实、链接和项目边界</li><li>删除模型猜测和无法确认的结论</li><li>确认没有密钥、客户数据、本机路径或私密上下文</li><li>检查是否复制了受版权保护或由其他仓库维护的长篇内容</li><li>对最终修改和影响负责</li></ul><p>Agent 生成不等于验证完成。PR 中应写明实际核对过什么。</p><h2 id="内容放置" tabindex="-1">内容放置 <a class="header-anchor" href="#内容放置" aria-label="Permalink to &quot;内容放置&quot;">​</a></h2><table tabindex="0"><thead><tr><th>内容</th><th>位置</th></tr></thead><tbody><tr><td>组织实践和文档治理</td><td><code>practices/</code></td></tr><tr><td>跨项目通用工程实践</td><td><code>practices/</code></td></tr><tr><td>AI Native 原则、工具和工作流</td><td><code>ai-native/</code></td></tr><tr><td>项目边界和跨仓库契约</td><td><code>projects/&lt;project&gt;/</code></td></tr></tbody></table><p>更详细的路由以 <code>WORKSPACE.md</code> 和 <code>SOURCE_OF_TRUTH.md</code> 为准。</p><h2 id="安全与隐私" tabindex="-1">安全与隐私 <a class="header-anchor" href="#安全与隐私" aria-label="Permalink to &quot;安全与隐私&quot;">​</a></h2><p>本仓库是公共 Handbook。不得提交：</p><ul><li>Token、密钥、账号和生产凭据</li><li>客户、用户、员工的私密信息</li><li>未脱敏的会议记录、事故日志和经营数据</li><li>内部访问地址和本机绝对路径</li><li>未经授权公开的私有仓库内容</li></ul><p>需要以私密证据支撑结论时，在 PR 中描述脱敏后的结论和证据类型，不复制原始数据。</p><h2 id="review-指南" tabindex="-1">Review 指南 <a class="header-anchor" href="#review-指南" aria-label="Permalink to &quot;Review 指南&quot;">​</a></h2><p>Reviewer 优先检查：</p><ol><li>内容是否放在正确层级。</li><li>事实、建议和待验证假设是否区分。</li><li>是否出现重复真源或过度复制。</li><li>状态是否与证据匹配。</li><li>受影响的 Owner 和项目是否知情。</li><li>链接和目录索引是否同步。</li><li>是否包含不应公开的信息。</li></ol><p>Review 可以挑战结论，但应给出原因、反例或更合适的归属建议。</p><h2 id="合并后的维护" tabindex="-1">合并后的维护 <a class="header-anchor" href="#合并后的维护" aria-label="Permalink to &quot;合并后的维护&quot;">​</a></h2><p>文档不是合并后永久有效。遇到实现冲突、工具升级、项目边界变化或新反例时，任何成员都可以发起后续修订、降级或废弃。</p>`,46)])])}const b=i(d,[["render",o]]);export{u as __pageData,b as default};
